What does the following program print?

```cpp
#include <iostream>
constexpr int count_digits(int n) {
    int count = 0;
    while (n > 0) {
        ++count;
        n /= 10;
    }
    return count;
}
int main() {
    constexpr int a = count_digits(12345);
    std::cout << a << "\n";
    std::cout << count_digits(9) << "\n";
}
```

